function Component({ canvas }) {
  const chat = canvas.chat;
  const [me, setMe] = React.useState(null);
  const [messages, setMessages] = React.useState(() => [...chat.history()]);
  const [draft, setDraft] = React.useState("");
  const [nameDraft, setNameDraft] = React.useState("");
  const [editingName, setEditingName] = React.useState(false);
  const listRef = React.useRef(null);

  React.useEffect(() => chat.identity(setMe), []);

  // Backfill from the retained log, then append each new line (deduped by msgId
  // so the history/subscribe gap can't double-post).
  React.useEffect(() => {
    setMessages([...chat.history()]);
    return chat.subscribe((entry) =>
      setMessages((m) => (m.some((x) => x.msgId === entry.msgId) ? m : [...m, entry]))
    );
  }, []);

  // While not actively editing, keep the name field showing our current name.
  React.useEffect(() => {
    if (me && !editingName) setNameDraft(me.name);
  }, [me, editingName]);

  // Keep the newest message in view.
  React.useEffect(() => {
    const el = listRef.current;
    if (el) el.scrollTop = el.scrollHeight;
  }, [messages]);

  const send = () => {
    const t = draft.trim();
    if (!t) return;
    chat.send(t);
    setDraft("");
  };

  const commitName = () => {
    setEditingName(false);
    const n = nameDraft.trim();
    if (n && me && n !== me.name) chat.setName(n);
    else if (me) setNameDraft(me.name);
  };

  const fieldStyle = {
    fontSize: 13, padding: "5px 8px",
    border: "1px solid var(--pc-border-mid)", borderRadius: 6,
    background: "var(--pc-input-bg)", color: "var(--pc-text)",
  };

  return (
    <div style={{ flex: 1, display: "flex", flexDirection: "column", minHeight: 0, gap: 6, height: "100%" }}>
      <div ref={listRef} style={{ flex: 1, minHeight: 0, overflow: "auto" }}>
        {messages.length === 0 ? (
          <div style={{ fontSize: 12, color: "var(--pc-faint2)", fontStyle: "italic", padding: 4 }}>
            no messages yet — say hello
          </div>
        ) : (
          messages.map((m) => (
            <div key={m.msgId} style={{ fontSize: 13, lineHeight: 1.4, marginBottom: 3, wordBreak: "break-word" }}>
              <span style={{ fontWeight: 700, color: m.color || "var(--pc-text)" }}>
                {m.name}{me && m.id === me.id ? " (you)" : ""}:
              </span>{" "}
              <span style={{ color: "var(--pc-text)" }}>{m.text}</span>
            </div>
          ))
        )}
      </div>

      <div style={{ display: "flex", gap: 6, alignItems: "center" }}>
        <span style={{ fontSize: 11, color: "var(--pc-muted)" }}>name</span>
        <input
          value={nameDraft}
          onChange={(e) => setNameDraft(e.target.value)}
          onFocus={() => setEditingName(true)}
          onBlur={commitName}
          onKeyDown={(e) => { if (e.key === "Enter") e.currentTarget.blur(); }}
          maxLength={24}
          style={{ ...fieldStyle, flex: 1, minWidth: 0 }}
          title="your display name — edit and press Enter" />
      </div>

      <div style={{ display: "flex", gap: 6 }}>
        <input
          value={draft}
          onChange={(e) => setDraft(e.target.value)}
          onKeyDown={(e) => { if (e.key === "Enter") send(); }}
          placeholder="message…"
          style={{ ...fieldStyle, flex: 1, minWidth: 0 }} />
        <button onClick={send} style={{
          padding: "5px 12px", border: "none", borderRadius: 6, fontSize: 13,
          fontWeight: 600, cursor: "pointer", background: "var(--pc-accent)",
          color: "var(--pc-accent-text)",
        }}>Send</button>
      </div>
    </div>
  );
}

function Component({ canvas, props }) {
  const [busy, setBusy] = React.useState(false);
  async function go() {
    if (busy) return;
    setBusy(true);
    try {
      const r = await canvas.request({});
      if (r && r.url) {
        const a = document.createElement("a");
        a.href = r.url;
        if (r.filename) a.download = r.filename;
        document.body.appendChild(a);
        a.click();
        a.remove();
      }
    } catch (e) {
      console.error("danvas download failed:", e);
    } finally {
      setBusy(false);
    }
  }
  return (
    <>
      <style>{`
.pc-download{box-sizing:border-box;width:100%;height:100%;padding:8px 12px;
 display:flex;align-items:center;justify-content:center;gap:8px;
 font:600 13px system-ui,-apple-system,sans-serif;color:var(--pc-off-text);
 background:var(--pc-off-bg);border:1px solid var(--pc-border);
 border-radius:8px;cursor:pointer;transition:background .12s}
.pc-download:hover{background:var(--pc-border-mid)}
.pc-download:active{transform:translateY(1px)}
.pc-download:disabled{opacity:.6;cursor:default}
.pc-download-ico{font-size:15px;line-height:1}
`}</style>
      <button className="pc-download" disabled={busy} onClick={go}>
        <span className="pc-download-ico">{"\u2913"}</span>
        {busy ? "Preparing\u2026" : props.text}
      </button>
    </>
  );
}

function Component({ canvas, value }) {
  React.useEffect(() => { canvas.send({ event: "ready" }); }, []);
  const state = value || { cwd: "/", atRoot: true, selected: null, entries: [] };
  function fmtSize(n) {
    if (!n) return "";
    const u = ["B", "KB", "MB", "GB", "TB"];
    let i = 0;
    while (n >= 1024 && i < u.length - 1) { n /= 1024; i++; }
    return (i ? n.toFixed(1) : n) + " " + u[i];
  }
  return (
    <div className="pc-fb">
      <style>{`
.pc-fb{height:100%;box-sizing:border-box;display:flex;flex-direction:column;
 font-family:system-ui,sans-serif;font-size:13px;background:#0f172a;color:#e2e8f0}
.pc-fb-bar{display:flex;align-items:center;gap:6px;padding:6px 8px;
 background:#1e293b;border-bottom:1px solid #334155;flex:none}
.pc-fb-up{cursor:pointer;border:1px solid #475569;background:#0f172a;
 color:#e2e8f0;border-radius:4px;padding:2px 8px;line-height:1.4}
.pc-fb-up:disabled{opacity:.35;cursor:default}
.pc-fb-cwd{font-family:ui-monospace,monospace;color:#94a3b8;overflow:hidden;
 text-overflow:ellipsis;white-space:nowrap;direction:rtl;text-align:left;flex:1}
.pc-fb-list{flex:1;overflow-y:auto}
.pc-fb-row{display:flex;align-items:center;gap:8px;padding:4px 10px;
 cursor:pointer;user-select:none}
.pc-fb-row:hover{background:#1e293b}
.pc-fb-row.sel{background:#1d4ed8}
.pc-fb-ico{width:16px;text-align:center;flex:none}
.pc-fb-nm{overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1}
.pc-fb-sz{color:#64748b;font-variant-numeric:tabular-nums;flex:none}
.pc-fb-row.sel .pc-fb-sz{color:#cbd5e1}
.pc-fb-empty{padding:12px;color:#64748b}
`}</style>
      <div className="pc-fb-bar">
        <button className="pc-fb-up" disabled={state.atRoot} title="up one level"
                onClick={() => canvas.send({ event: "up" })}>..</button>
        <span className="pc-fb-cwd">{state.cwd}</span>
      </div>
      <div className="pc-fb-list">
        {state.entries.length === 0
          ? <div className="pc-fb-empty">(empty)</div>
          : state.entries.map((ent, i) => (
              <div key={i} role="button"
                   className={"pc-fb-row" + (!ent.dir && ent.name === state.selected ? " sel" : "")}
                   onClick={() => canvas.send({ event: "open", name: ent.name })}>
                <span className="pc-fb-ico">{ent.dir ? "📁" : "📄"}</span>
                <span className="pc-fb-nm">{ent.name}</span>
                <span className="pc-fb-sz">{ent.dir ? "" : fmtSize(ent.size)}</span>
              </div>
            ))}
      </div>
    </div>
  );
}

function Component({ canvas, props }) {
  const Plotly = libs.plotly;
  const nodeRef = React.useRef(null);
  const fig = props && props._fig;
  React.useEffect(() => {
    const node = nodeRef.current;
    if (!node) return;
    let raf = null;
    let ro = null;
    if (typeof ResizeObserver !== "undefined") {
      ro = new ResizeObserver(() => {
        if (raf) return;
        raf = requestAnimationFrame(() => { raf = null; if (nodeRef.current) Plotly.Plots.resize(nodeRef.current); });
      });
      ro.observe(node);
    }
    return () => {
      if (ro) ro.disconnect();
      if (raf) cancelAnimationFrame(raf);
      if (nodeRef.current) Plotly.purge(nodeRef.current);
    };
  }, []);
  React.useEffect(() => {
    const node = nodeRef.current;
    if (!node || !fig) return;
    // Omitting displayModeBar gives Plotly's hover-reveal toolbar (zoom, pan,
    // box-zoom, autoscale, reset, download-PNG) — the analysis tools researchers
    // expect on a chart. displaylogo:false drops the Plotly link. Full button set
    // is kept: Plot renders arbitrary figures (incl. scatter, where box/lasso
    // select are meaningful).
    Plotly.react(node, fig.data || [], fig.layout || {}, { responsive: true, displaylogo: false });
  });
  return (
    <div style={{ flex: 1, width: "100%", minHeight: 0, position: "relative" }}>
      {!fig && (
        <div style={{ position: "absolute", inset: 0, display: "flex", alignItems: "center", justifyContent: "center", color: "var(--pc-muted, #9ca3af)", fontSize: 13 }}>
          no data yet
        </div>
      )}
      <div ref={nodeRef} style={{ width: "100%", height: "100%" }} />
    </div>
  );
}

